type ScreenMode = 'menu' | 'gallery' | 'counting' | 'addition';

/** Generate an addition problem with sum <= 10 */
function generateAddition\(\): { a: number; b: number; options: number[]; emoji: string } {
  const sum = Math.floor\(Math.random\(\) * 9\) + 2; // 2-10
  const a = Math.floor\(Math.random\(\) * \(sum - 1\)\) + 1;
  const b = sum - a;

  const options = new Set<number>\([sum]\);
  while \(options.size < 3\) {
    const offset = Math.random\(\) > 0.5 ? 1 : -1;
    const delta = Math.floor\(Math.random\(\) * 3\) + 1;
    const val = sum + offset * delta;
    if \(val > 0 && val <= 15\) {
      options.add\(val\);
    }
  }

  return {
    a,
    b,
    options: Array.from\(options\).sort\(\(\) => Math.random\(\) - 0.5\),
    emoji: getRandomEmoji\(\),
  };
}

const PREVIEW_NUMBERS = NUMBERS.slice\(0, 5\);

const PASTEL_CIRCLES = ['#FFB5B5', '#B5D8FF', '#B5FFD8', '#FFF5B5', '#D8B5FF'];

export default function NumberJungleScreen\(\) {
  const [mode, setMode] = useState<ScreenMode>\('menu'\);
  const { width: screenWidth } = useWindowDimensions\(\);
  const { completeLevel } = useProgress\('numberJungle'\);
  const sound = useSound\(\);

  // Counting game state
  const [countingRound, setCountingRound] = useState\(0\);
  const [countingDifficulty, setCountingDifficulty] = useState\(3\); // starts at 3

  // Addition game state
  const [additionRound, setAdditionRound] = useState\(0\);
  const [additionScore, setAdditionScore] = useState\(0\);
  const [additionTotal, setAdditionTotal] = useState\(0\);
  const [showAdditionResult, setShowAdditionResult] = useState\(false\);

  // Generate counting target
  const countingTarget = useMemo\(
    \(\) => Math.min\(countingDifficulty, 15\),
    [countingDifficulty]
  \);
  const countingEmoji = useMemo\(\(\) => getRandomEmoji\(\), [countingRound]\);

  // Generate addition problem
  const additionProblem = useMemo\(\(\) => generateAddition\(\), [additionRound]\);

  // Calculate number card size for 3-column grid
  const numberCardSize = useMemo\(
    \(\) => \(screenWidth - SPACING.md * 2 - SPACING.sm * 2\) / 3,
    [screenWidth]
  \);

  const handleCountingComplete = useCallback\(
    \(stars: number\) => {
      completeLevel\(`counting-${countingRound}`, stars\);
      sound.playStar\(\);

      setTimeout\(\(\) => {
        setCountingRound\(\(r\) => r + 1\);
        // Gradually increase difficulty
        setCountingDifficulty\(\(d\) => Math.min\(d + 1, 15\)\);
      }, 3000\);
    },
    [countingRound, completeLevel, sound]
  \);

  const handleAdditionComplete = useCallback\(
    \(correct: boolean\) => {
      setAdditionTotal\(\(t\) => t + 1\);
      if \(correct\) {
        setAdditionScore\(\(s\) => s + 1\);
      }

      // After 5 problems, show result
      if \(additionTotal + 1 >= 5\) {
        const finalScore = additionScore + \(correct ? 1 : 0\);
        const stars = finalScore >= 5 ? 3 : finalScore >= 3 ? 2 : 1;
        completeLevel\(`addition-set-${additionRound}`, stars\);
        sound.playStar\(\);

        setTimeout\(\(\) => {
          setShowAdditionResult\(true\);
        }, 1500\);
      } else {
        // Next problem
        setTimeout\(\(\) => {
          setAdditionRound\(\(r\) => r + 1\);
        }, 1500\);
      }
    },
    [additionTotal, additionScore, additionRound, completeLevel, sound]
  \);

  const handleNewAdditionSet = useCallback\(\(\) => {
    setAdditionRound\(\(r\) => r + 1\);
    setAdditionScore\(0\);
    setAdditionTotal\(0\);
    setShowAdditionResult\(false\);
  }, []\);

  const handleNumberPress = useCallback\(
    \(num: { value: number }\) => {
      sound.playTap\(\);
    },
    [sound]
  \);

  const additionStars = additionScore >= 5 ? 3 : additionScore >= 3 ? 2 : 1;

  const handleBack = useCallback\(\(\) => {
    setMode\('menu'\);
  }, []\);

  return \(
    <View style={styles.container}>
      <GameHeader
        title={S.numberJungle.id}
        subtitle={S.numberJungle.en}
        color={COLORS.numberJungle}
      />

      {/* ========== MENU MODE ========== */}
      {mode === 'menu' && \(
        <ScrollView
          style={styles.scrollView}
          contentContainerStyle={styles.menuContent}
          showsVerticalScrollIndicator={false}
        >
          {/* Activity Card 1: Gallery */}
          <ActivityCard
            emoji="🔢"
            title="Galeri Angka"
            subtitle="Number Gallery"
            backgroundColor={COLORS.green}
            index={0}
            onPress={\(\) => setMode\('gallery'\)}
          />

          {/* Activity Card 2: Counting */}
          <ActivityCard
            emoji="👆"
            title="Hitung Benda"
            subtitle="Count Objects"
            backgroundColor={COLORS.yellow}
            index={1}
            onPress={\(\) => setMode\('counting'\)}
          />

          {/* Activity Card 3: Addition */}
          <ActivityCard
            emoji="➕"
            title="Penjumlahan"
            subtitle="Addition"
            backgroundColor={COLORS.orange}
            index={2}
            onPress={\(\) => {
              setMode\('addition'\);
              handleNewAdditionSet\(\);
            }}
          />

          {/* Preview row of numbers 1-5 */}
          <Animated.View
            entering={FadeInDown.delay\(400\).duration\(500\)}
            style={styles.previewRow}
          >
            {PREVIEW_NUMBERS.map\(\(num, i\) => \(
              <View
                key={num.value}
                style={[
                  styles.previewCircle,
                  { backgroundColor: PASTEL_CIRCLES[i] },
                ]}
              >
                <Text style={styles.previewNumber}>{num.value}</Text>
              </View>
            \)\)}
          </Animated.View>
        </ScrollView>
      \)}

      {/* ========== GALLERY MODE ========== */}
      {mode === 'gallery' && \(
        <View style={styles.activityContainer}>
          <BackButton onPress={handleBack} />
          <ScrollView
            style={styles.scrollView}
            contentContainerStyle={styles.grid}
            showsVerticalScrollIndicator={false}
          >
            {NUMBERS.map\(\(num\) => \(
              <NumberCard
                key={num.value}
                number={num}
                onPress={handleNumberPress}
                size={numberCardSize}
              />
            \)\)}
          </ScrollView>
        </View>
      \)}

      {/* ========== COUNTING MODE ========== */}
      {mode === 'counting' && \(
        <View style={styles.activityContainer}>
          <BackButton onPress={handleBack} />
          <View style={styles.gameContainer}>
            <CountingGame
              key={`counting-${countingRound}`}
              targetCount={countingTarget}
              emoji={countingEmoji}
              onComplete={handleCountingComplete}
            />

            <Pressable
              style={styles.newRoundButton}
              onPress={\(\) => {
                setCountingRound\(\(r\) => r + 1\);
              }}
            >
              <Text style={styles.newRoundText}>
                {S.retry.id} / {S.retry.en}
              </Text>
            </Pressable>
          </View>
        </View>
      \)}

      {/* ========== ADDITION MODE ========== */}
      {mode === 'addition' && !showAdditionResult && \(
        <View style={styles.activityContainer}>
          <BackButton onPress={handleBack} />
          <View style={styles.gameContainer}>
            {/* Progress indicator */}
            <View style={styles.progressRow}>
              {Array.from\({ length: 5 }\).map\(\(_, i\) => \(
                <View
                  key={i}
                  style={[
                    styles.progressDot,
                    i < additionTotal && styles.progressDotDone,
                    i === additionTotal && styles.progressDotCurrent,
                  ]}
                />
              \)\)}
            </View>

            <AdditionGame
              key={`add-${additionRound}`}
              a={additionProblem.a}
              b={additionProblem.b}
              options={additionProblem.options}
              emoji={additionProblem.emoji}
              onComplete={handleAdditionComplete}
            />
          </View>
        </View>
      \)}

      {mode === 'addition' && showAdditionResult && \(
        <View style={styles.activityContainer}>
          <BackButton onPress={handleBack} />
          <View style={styles.resultContainer}>
            <View style={styles.resultCard}>
              <Text style={styles.resultTitle}>{S.wellDone.id}</Text>
              <Text style={styles.resultTitleEn}>{S.wellDone.en}</Text>
              <Text style={styles.scoreText}>
                {additionScore} / 5
              </Text>
              <StarReward stars={additionStars} size={48} animate={true} />
              <Pressable
                style={styles.playAgainButton}
                onPress={handleNewAdditionSet}
              >
                <Text style={styles.playAgainText}>
                  {S.retry.id} / {S.retry.en}
                </Text>
              </Pressable>
            </View>

            <ConfettiOverlay visible={true} />
          </View>
        </View>
      \)}
    </View>
  \);
}

/* ========== Activity Card Component ========== */

function ActivityCard\({
  emoji,
  title,
  subtitle,
  backgroundColor,
  index,
  onPress,
}: {
  emoji: string;
  title: string;
  subtitle: string;
  backgroundColor: string;
  index: number;
  onPress: \(\) => void;
}\) {
  const scale = useSharedValue\(1\);

  const animatedStyle = useAnimatedStyle\(\(\) => \({
    transform: [{ scale: scale.value }],
  }\)\);

  return \(
    <Pressable
      onPress={onPress}
      onPressIn={\(\) => {
        scale.value = withSpring\(0.96, { damping: 15, stiffness: 300 }\);
      }}
      onPressOut={\(\) => {
        scale.value = withSpring\(1, { damping: 10, stiffness: 200 }\);
      }}
    >
      <Animated.View
        entering={FadeInDown.delay\(index * 120\).duration\(400\)}
        style={[
          styles.activityCard,
          { backgroundColor },
          animatedStyle,
        ]}
      >
        <Text style={styles.activityEmoji}>{emoji}</Text>
        <View style={styles.activityTextContainer}>
          <Text style={styles.activityTitle}>{title}</Text>
          <Text style={styles.activitySubtitle}>{subtitle}</Text>
        </View>
        <Text style={styles.activityArrow}>→</Text>
      </Animated.View>
    </Pressable>
  \);
}

/* ========== Back Button Component ========== */

function BackButton\({ onPress }: { onPress: \(\) => void }\) {
  const scale = useSharedValue\(1\);

  const animatedStyle = useAnimatedStyle\(\(\) => \({
    transform: [{ scale: scale.value }],
  }\)\);

  return \(
    <Pressable
      onPress={onPress}
      onPressIn={\(\) => {
        scale.value = withSpring\(0.9, { damping: 15, stiffness: 300 }\);
      }}
      onPressOut={\(\) => {
        scale.value = withSpring\(1, { damping: 10, stiffness: 200 }\);
      }}
      style={styles.backButtonPressable}
    >
      <Animated.View style={[styles.backButton, animatedStyle]}>
        <Text style={styles.backButtonText}>← {S.back.id}</Text>
      </Animated.View>
    </Pressable>
  \);
}

